// SVG Path Drawing with GSAP
const paths = svgRef.current.querySelectorAll('path')
paths.forEach(path => {
  const length = path.getTotalLength()
  gsap.set(path, {
    strokeDasharray: length,
    strokeDashoffset: length,
  })
  gsap.to(path, {
    strokeDashoffset: 0,
    duration: 2,
    ease: 'power2.inOut',
    scrollTrigger: {
      trigger: path,
      start: 'top 80%',
      once: true
    }
  })
})

